import{_ as n,C as l,o as i,c as r,a2 as t,b as s,w as a,a as c,E as d,a3 as u}from"./chunks/framework.B72_uj9U.js";const x=JSON.parse('{"title":"Voice and Multimodal Streaming","description":"","frontmatter":{},"headers":[],"relativePath":"research/concepts/streaming/voice-and-multimodal.md","filePath":"research/concepts/streaming/voice-and-multimodal.md"}'),p={name:"research/concepts/streaming/voice-and-multimodal.md"};function m(h,e,g,f,b,v){const o=l("Mermaid");return i(),r("div",null,[e[1]||(e[1]=t('<h1 id="voice-and-multimodal-streaming" tabindex="-1">Voice and Multimodal Streaming <a class="header-anchor" href="#voice-and-multimodal-streaming" aria-label="Permalink to &quot;Voice and Multimodal Streaming&quot;">​</a></h1><p>Beyond text: voice coding, multimodal inputs, and future streaming modalities.</p><hr><h2 id="_1-voice-coding-with-aider" tabindex="-1">1. Voice Coding with Aider <a class="header-anchor" href="#_1-voice-coding-with-aider" aria-label="Permalink to &quot;1. Voice Coding with Aider&quot;">​</a></h2><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><ul><li>Speech-to-text pipeline: microphone → transcription → text prompt</li><li>Aider&#39;s <code>--voice</code> flag activates voice mode</li><li>Uses OpenAI Whisper API for transcription</li><li>Flow: Record → Transcribe → Send to LLM → Stream response → Apply edits</li><li>User speaks natural language coding instructions</li><li>LLM interprets and generates code edits</li><li>The voice input substitutes for typed prompts — all downstream processing remains identical</li></ul><h3 id="technical-architecture" tabindex="-1">Technical Architecture <a class="header-anchor" href="#technical-architecture" aria-label="Permalink to &quot;Technical Architecture&quot;">​</a></h3><ul><li>Audio capture via system microphone using platform APIs</li><li>Audio format: WAV or WebM depending on platform</li><li>Whisper API call: <code>POST /v1/audio/transcriptions</code> with audio file</li><li>Transcription latency: typically 1-3 seconds for short utterances</li><li>Combined with Aider&#39;s edit format parsing (search/replace blocks, whole files, etc.)</li><li>Voice input replaces keyboard for prompt entry only — the edit loop is unchanged</li><li>No persistent audio connection; each utterance is a discrete API call</li></ul><h3 id="benefits" tabindex="-1">Benefits <a class="header-anchor" href="#benefits" aria-label="Permalink to &quot;Benefits&quot;">​</a></h3><ul><li>Hands-free coding for ergonomic relief</li><li>Natural language instructions feel more intuitive for describing intent</li><li>Faster for describing complex, multi-step changes than typing</li><li>Accessibility for motor-impaired developers who cannot use a keyboard effectively</li><li>Reduces context-switching between thinking and typing</li><li>Pairs well with standing desks and non-traditional workstations</li></ul><h3 id="limitations" tabindex="-1">Limitations <a class="header-anchor" href="#limitations" aria-label="Permalink to &quot;Limitations&quot;">​</a></h3><ul><li>Transcription errors, especially for code-specific terms (variable names, APIs, syntax)</li><li>Background noise sensitivity degrades transcription accuracy</li><li>No voice output — responses remain text-only in the terminal</li><li>Cumulative latency: voice capture → transcription → LLM generation → response streaming</li><li>Better for high-level instructions than dictating exact code syntax</li><li>Whisper API costs add to per-request expense</li><li>No streaming of transcription — must wait for full utterance to complete</li></ul><hr><h2 id="_2-openai-realtime-api" tabindex="-1">2. OpenAI Realtime API <a class="header-anchor" href="#_2-openai-realtime-api" aria-label="Permalink to &quot;2. OpenAI Realtime API&quot;">​</a></h2><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><ul><li>WebSocket connection: <code>wss://api.openai.com/v1/realtime</code></li><li>Bidirectional: client sends audio/text, server sends audio/text simultaneously</li><li>Event-based protocol over WebSocket frames</li><li>Persistent connection for the duration of a conversation session</li><li>Supports both text and audio modalities in a single session</li><li>Model: <code>gpt-4o-realtime-preview</code> (purpose-built for low-latency voice)</li></ul><h3 id="session-events-client-→-server" tabindex="-1">Session Events (Client → Server) <a class="header-anchor" href="#session-events-client-→-server" aria-label="Permalink to &quot;Session Events (Client → Server)&quot;">​</a></h3><ul><li><code>session.create</code> / <code>session.update</code> — configure session parameters, tools, voice</li><li><code>input_audio_buffer.append</code> — send raw audio data chunks</li><li><code>input_audio_buffer.commit</code> — signal that the audio input is complete</li><li><code>input_audio_buffer.clear</code> — discard buffered audio</li><li><code>conversation.item.create</code> — inject text or audio items into conversation</li><li><code>response.create</code> — explicitly trigger a model response</li><li><code>response.cancel</code> — cancel an in-progress response</li></ul><h3 id="server-events-server-→-client" tabindex="-1">Server Events (Server → Client) <a class="header-anchor" href="#server-events-server-→-client" aria-label="Permalink to &quot;Server Events (Server → Client)&quot;">​</a></h3><ul><li><code>session.created</code> / <code>session.updated</code> — confirm session configuration</li><li><code>input_audio_buffer.speech_started</code> — VAD detected speech onset</li><li><code>input_audio_buffer.speech_stopped</code> — VAD detected speech end</li><li><code>response.audio.delta</code> — audio output chunks (base64-encoded PCM)</li><li><code>response.audio_transcript.delta</code> — text transcript of the audio being generated</li><li><code>response.text.delta</code> — text output chunks (when in text mode)</li><li><code>response.function_call_arguments.delta</code> — streaming tool call arguments</li><li><code>response.done</code> — response generation complete</li><li><code>rate_limits.updated</code> — current rate limit status</li><li><code>error</code> — error information</li></ul><h3 id="audio-formats" tabindex="-1">Audio Formats <a class="header-anchor" href="#audio-formats" aria-label="Permalink to &quot;Audio Formats&quot;">​</a></h3><ul><li><strong>PCM16</strong>: 16-bit PCM audio at 24kHz sample rate, little-endian byte order</li><li><strong>G.711 μ-law</strong>: 8kHz telephony encoding, smaller payloads, lower quality</li><li><strong>G.711 A-law</strong>: alternative telephony encoding used in European systems</li><li>Input and output formats are configured independently in the session</li></ul><h3 id="voice-activity-detection-vad" tabindex="-1">Voice Activity Detection (VAD) <a class="header-anchor" href="#voice-activity-detection-vad" aria-label="Permalink to &quot;Voice Activity Detection (VAD)&quot;">​</a></h3><ul><li><strong>Server-side VAD</strong>: the API detects when the user starts and stops speaking <ul><li>Automatically commits audio buffer on silence detection</li><li>Configurable silence threshold (duration of silence to trigger commit)</li><li>Prefix padding: how much audio before speech onset to include</li><li>Suffix padding: how much silence after speech end before committing</li></ul></li><li><strong>Client-side VAD</strong>: the application controls audio boundaries explicitly <ul><li>Application calls <code>input_audio_buffer.commit</code> manually</li><li>Useful when VAD needs to be customized or combined with UI controls</li></ul></li><li><code>turn_detection</code> configuration in session setup selects the mode</li></ul><h3 id="function-calling-in-realtime" tabindex="-1">Function Calling in Realtime <a class="header-anchor" href="#function-calling-in-realtime" aria-label="Permalink to &quot;Function Calling in Realtime&quot;">​</a></h3><ul><li>Define tools in session configuration (same schema as Chat Completions)</li><li>Model can invoke functions mid-conversation during voice interaction</li><li>Function call arguments arrive via <code>response.function_call_arguments.delta</code> events</li><li>Client-side code executes the function and sends the result back</li><li>Conversation continues seamlessly with the function result in context</li><li>Enables voice-driven tool use: &quot;run my tests&quot;, &quot;search for that function&quot;, etc.</li></ul><h3 id="use-cases-for-coding-agents" tabindex="-1">Use Cases for Coding Agents <a class="header-anchor" href="#use-cases-for-coding-agents" aria-label="Permalink to &quot;Use Cases for Coding Agents&quot;">​</a></h3><ul><li>Voice-driven code generation and editing</li><li>Real-time pair programming with bidirectional voice</li><li>Debugging via verbal description of symptoms</li><li>Code review discussion with voice Q&amp;A about diffs</li><li>Hands-free CI/CD pipeline management</li><li>Architecture brainstorming sessions</li></ul><h3 id="codex-cli-and-realtime-api" tabindex="-1">Codex CLI and Realtime API <a class="header-anchor" href="#codex-cli-and-realtime-api" aria-label="Permalink to &quot;Codex CLI and Realtime API&quot;">​</a></h3><ul><li>Codex CLI has a <code>supports_websockets</code> flag per provider configuration</li><li>Explicit WebSocket transport support for realtime streaming mode</li><li>Integration with the Responses API streaming infrastructure</li><li>Potential for voice-first coding workflows built on Codex</li></ul><hr><h2 id="_3-multimodal-streaming-images-in-coding-context" tabindex="-1">3. Multimodal Streaming: Images in Coding Context <a class="header-anchor" href="#_3-multimodal-streaming-images-in-coding-context" aria-label="Permalink to &quot;3. Multimodal Streaming: Images in Coding Context&quot;">​</a></h2><h3 id="screenshot-image-input" tabindex="-1">Screenshot/Image Input <a class="header-anchor" href="#screenshot-image-input" aria-label="Permalink to &quot;Screenshot/Image Input&quot;">​</a></h3><ul><li>Send screenshots of error messages, UI states, or design mockups</li><li>LLM analyzes the image content and generates corresponding code</li><li>Useful for: UI matching (screenshot → CSS/HTML), error debugging, diagram-to-code</li><li>Images are embedded in the message content array alongside text</li></ul><h3 id="how-streaming-works-with-images" tabindex="-1">How Streaming Works with Images <a class="header-anchor" href="#how-streaming-works-with-images" aria-label="Permalink to &quot;How Streaming Works with Images&quot;">​</a></h3><ul><li>Images are sent as base64-encoded data in the request payload (not streamed incrementally)</li><li>The response streams back as normal text tokens via SSE or WebSocket</li><li>Larger image payloads → longer time-to-first-token due to vision processing</li><li>Image tokens count toward the model&#39;s context window (token cost varies by resolution)</li><li>Multiple images can be sent in a single request for comparison or context</li></ul><h3 id="agent-support-for-image-input" tabindex="-1">Agent Support for Image Input <a class="header-anchor" href="#agent-support-for-image-input" aria-label="Permalink to &quot;Agent Support for Image Input&quot;">​</a></h3><ul><li><strong>Claude Code</strong>: supports image input via clipboard paste or file reference in prompts</li><li><strong>Gemini CLI</strong>: native multimodal input support including images, video, and audio</li><li><strong>OpenAI</strong>: Vision API supports images in Chat Completions and Responses API messages</li><li><strong>Aider</strong>: image support specifically for UI development workflows (screenshot → code)</li><li><strong>Cursor/Windsurf</strong>: IDE-integrated image attachment in chat panels</li></ul><hr><h2 id="_4-gemini-s-multimodal-capabilities" tabindex="-1">4. Gemini&#39;s Multimodal Capabilities <a class="header-anchor" href="#_4-gemini-s-multimodal-capabilities" aria-label="Permalink to &quot;4. Gemini&#39;s Multimodal Capabilities&quot;">​</a></h2><h3 id="native-multimodal-processing" tabindex="-1">Native Multimodal Processing <a class="header-anchor" href="#native-multimodal-processing" aria-label="Permalink to &quot;Native Multimodal Processing&quot;">​</a></h3><ul><li>Text, images, video, and audio are all first-class input modalities</li><li>1M+ token context window accommodates multimodal token counts</li><li>Video understanding: analyze recorded code demos, tutorials, or bug reproductions</li><li>Audio processing: transcribe and analyze voice recordings, meeting notes</li><li>PDF and document understanding: process technical specifications directly</li></ul><h3 id="streaming-with-multimodal-input" tabindex="-1">Streaming with Multimodal Input <a class="header-anchor" href="#streaming-with-multimodal-input" aria-label="Permalink to &quot;Streaming with Multimodal Input&quot;">​</a></h3><ul><li>Multimodal tokens (image, video, audio) affect time-to-first-token significantly</li><li>Large video files may add 5-15 seconds of processing latency before streaming begins</li><li>Streaming output is currently text-based regardless of input modality</li><li>Future roadmap includes multimodal output (generated images, diagrams, audio)</li><li>Token counting for multimodal inputs follows per-modality formulas</li></ul><h3 id="code-specific-multimodal-uses" tabindex="-1">Code-Specific Multimodal Uses <a class="header-anchor" href="#code-specific-multimodal-uses" aria-label="Permalink to &quot;Code-Specific Multimodal Uses&quot;">​</a></h3><ul><li>Screenshot → CSS/HTML generation (pixel-accurate UI reproduction)</li><li>Architecture diagram → code scaffolding and module structure</li><li>Video of a bug → reproduction steps and potential fix code</li><li>Whiteboard photo → algorithm implementation</li><li>Design mockup → component hierarchy and styled code</li><li>Error screenshot → debugging analysis and fix suggestions</li></ul><hr><h2 id="_5-gemini-live-api" tabindex="-1">5. Gemini Live API <a class="header-anchor" href="#_5-gemini-live-api" aria-label="Permalink to &quot;5. Gemini Live API&quot;">​</a></h2><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><ul><li>WebSocket-based real-time multimodal streaming API</li><li>Supports audio input and output in real-time bidirectional communication</li><li>Tool use (function calling) during live sessions</li><li>Session management with context preservation across turns</li><li>Ephemeral tokens for client-side security (short-lived, scoped credentials)</li></ul><h3 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h3><ul><li>Connection via <code>wss://</code> endpoint with model-specific paths</li><li>Audio streamed as raw PCM chunks in both directions</li><li>Server-side VAD for automatic turn detection</li><li>Supports interruption: user can speak while model is generating</li><li>Context window shared between audio and text tokens</li><li>Session configuration includes voice selection, tools, and system instructions</li></ul><h3 id="comparison-with-openai-realtime-api" tabindex="-1">Comparison with OpenAI Realtime API <a class="header-anchor" href="#comparison-with-openai-realtime-api" aria-label="Permalink to &quot;Comparison with OpenAI Realtime API&quot;">​</a></h3><ul><li>Both use WebSocket for bidirectional audio streaming</li><li>Gemini supports video input in live sessions (OpenAI does not yet)</li><li>Both support function calling during voice conversations</li><li>Different event schemas and session management approaches</li><li>Gemini&#39;s larger context window allows longer multimodal sessions</li></ul><hr><h2 id="_6-future-video-streaming-for-debugging" tabindex="-1">6. Future: Video Streaming for Debugging <a class="header-anchor" href="#_6-future-video-streaming-for-debugging" aria-label="Permalink to &quot;6. Future: Video Streaming for Debugging&quot;">​</a></h2><h3 id="screen-sharing-with-agents" tabindex="-1">Screen Sharing with Agents <a class="header-anchor" href="#screen-sharing-with-agents" aria-label="Permalink to &quot;Screen Sharing with Agents&quot;">​</a></h3><ul><li>Stream terminal or IDE output to an agent in real-time</li><li>Real-time code review: agent watches as you write and offers suggestions</li><li>Agent observes a debugging session and suggests fixes as issues appear</li><li>Potential: agent proactively helps by watching your coding patterns</li><li>Reduces the need to manually describe context — the agent sees what you see</li></ul><h3 id="technical-challenges" tabindex="-1">Technical Challenges <a class="header-anchor" href="#technical-challenges" aria-label="Permalink to &quot;Technical Challenges&quot;">​</a></h3><ul><li>Video encoding/decoding latency adds to round-trip time</li><li>Bandwidth requirements: even compressed screen capture is 1-5 Mbps</li><li>Frame analysis computation: extracting text/UI from video frames</li><li>Real-time response generation while processing continuous video input</li><li>Privacy concerns: screen content may include sensitive information</li><li>Cost: video tokens are expensive relative to text</li></ul><h3 id="emerging-approaches" tabindex="-1">Emerging Approaches <a class="header-anchor" href="#emerging-approaches" aria-label="Permalink to &quot;Emerging Approaches&quot;">​</a></h3><ul><li><strong>Computer Use APIs</strong> (Anthropic): agent controls mouse/keyboard on a virtual desktop</li><li><strong>Screenshot-based interaction</strong> (current state): periodic screenshots, not continuous video</li><li><strong>Project Mariner</strong> (Google): browser agent that navigates and interacts with web content</li><li>Future: continuous video stream analysis with sub-second response latency</li><li>Hybrid approaches: key-frame extraction rather than full video streaming</li></ul><hr><h2 id="_7-text-to-speech-output-for-agents" tabindex="-1">7. Text-to-Speech Output for Agents <a class="header-anchor" href="#_7-text-to-speech-output-for-agents" aria-label="Permalink to &quot;7. Text-to-Speech Output for Agents&quot;">​</a></h2><h3 id="current-state" tabindex="-1">Current State <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current State&quot;">​</a></h3><ul><li>Most coding agents produce text-only output in the terminal</li><li>Some wrapper applications pipe LLM text responses through TTS engines</li><li>OpenAI TTS API: <code>POST /v1/audio/speech</code> generates speech from text</li><li>Alternative TTS providers: ElevenLabs, Google Cloud TTS, Azure Cognitive Services</li><li>Streaming TTS: some APIs support chunked audio output for lower latency</li></ul><h3 id="for-coding-agents" tabindex="-1">For Coding Agents <a class="header-anchor" href="#for-coding-agents" aria-label="Permalink to &quot;For Coding Agents&quot;">​</a></h3><ul><li>Read code changes aloud while developer reviews visually</li><li>Explain diffs and architectural decisions verbally</li><li>Accessibility: essential for blind or low-vision developers using screen readers</li><li>Hands-free notification of task completion or error status</li><li>Background audio summaries while developer focuses on another task</li></ul><h3 id="technical-integration" tabindex="-1">Technical Integration <a class="header-anchor" href="#technical-integration" aria-label="Permalink to &quot;Technical Integration&quot;">​</a></h3><ul><li>TTS can be applied post-hoc to any text stream</li><li>Challenge: code syntax does not read well as speech (symbols, indentation)</li><li>Need intelligent summarization layer between raw code output and TTS</li><li>Latency budget: text generation + TTS synthesis + audio playback</li><li>Voice selection and customization for developer preference</li></ul><hr><h2 id="_8-accessibility-considerations" tabindex="-1">8. Accessibility Considerations <a class="header-anchor" href="#_8-accessibility-considerations" aria-label="Permalink to &quot;8. Accessibility Considerations&quot;">​</a></h2><h3 id="screen-reader-compatibility" tabindex="-1">Screen Reader Compatibility <a class="header-anchor" href="#screen-reader-compatibility" aria-label="Permalink to &quot;Screen Reader Compatibility&quot;">​</a></h3><ul><li>Terminal screen readers: NVDA (Windows), VoiceOver (macOS), Orca (Linux), JAWS</li><li>ANSI escape codes (colors, cursor movement) can confuse screen readers</li><li>Agents should provide semantic output alongside visual formatting</li><li><code>ACCESSIBILITY</code> or <code>NO_COLOR</code> environment variables signal preference for plain output</li><li>Progress indicators should use text-based updates, not just spinner animations</li></ul><h3 id="motor-accessibility" tabindex="-1">Motor Accessibility <a class="header-anchor" href="#motor-accessibility" aria-label="Permalink to &quot;Motor Accessibility&quot;">​</a></h3><ul><li>Voice input (Aider&#39;s <code>--voice</code> flag) reduces keyboard dependency</li><li>Eye tracking integration for cursor control (future possibility)</li><li>Switch access compatibility for users with limited motor function</li><li>Reduced keyboard shortcut requirements — prefer simple commands</li><li>Configurable confirmation modes (auto-approve for users who cannot easily type)</li></ul><h3 id="visual-accessibility" tabindex="-1">Visual Accessibility <a class="header-anchor" href="#visual-accessibility" aria-label="Permalink to &quot;Visual Accessibility&quot;">​</a></h3><ul><li>High contrast modes for terminal output</li><li>Configurable color schemes that respect system preferences</li><li>Font size independence — terminal font configuration is separate from agent</li><li>No color-only information conveyed — always include symbols or text labels</li><li>Diff output should use <code>+</code>/<code>-</code> prefixes, not just red/green coloring</li></ul><h3 id="cognitive-accessibility" tabindex="-1">Cognitive Accessibility <a class="header-anchor" href="#cognitive-accessibility" aria-label="Permalink to &quot;Cognitive Accessibility&quot;">​</a></h3><ul><li>Clear, predictable progress indicators (percentage, step counts)</li><li>Predictable behavior: same input produces same workflow</li><li>Undo/redo support for reverting agent-applied changes</li><li>Reduced information overload: configurable verbosity levels</li><li>Summaries before detailed output to help users decide what to read</li></ul><hr><h2 id="_9-streaming-protocol-implications-for-multimodal" tabindex="-1">9. Streaming Protocol Implications for Multimodal <a class="header-anchor" href="#_9-streaming-protocol-implications-for-multimodal" aria-label="Permalink to &quot;9. Streaming Protocol Implications for Multimodal&quot;">​</a></h2><h3 id="voice-streaming-requirements" tabindex="-1">Voice Streaming Requirements <a class="header-anchor" href="#voice-streaming-requirements" aria-label="Permalink to &quot;Voice Streaming Requirements&quot;">​</a></h3><ul><li><strong>Bidirectional communication</strong>: WebSocket required (SSE is server→client only)</li><li><strong>Low latency target</strong>: &lt;200ms round-trip for conversational feel</li><li><strong>Audio buffering</strong>: handle jitter and network variability</li><li><strong>VAD integration</strong>: detect speech boundaries for turn-taking</li><li><strong>Interruption handling</strong>: user should be able to interrupt model speech</li><li><strong>Codec negotiation</strong>: client and server agree on audio format</li></ul><h3 id="multimodal-input-challenges" tabindex="-1">Multimodal Input Challenges <a class="header-anchor" href="#multimodal-input-challenges" aria-label="Permalink to &quot;Multimodal Input Challenges&quot;">​</a></h3><ul><li>Large payloads: images (100KB-5MB), video (10MB-500MB), audio (1MB-50MB)</li><li>Base64 encoding overhead: ~33% size increase over binary</li><li>Chunked upload for large files to avoid timeout and memory issues</li><li>Separate upload endpoints with file references in prompts (preferred for large assets)</li><li>Token counting complexity: different formulas for each modality</li></ul><h3 id="protocol-comparison-for-multimodal" tabindex="-1">Protocol Comparison for Multimodal <a class="header-anchor" href="#protocol-comparison-for-multimodal" aria-label="Permalink to &quot;Protocol Comparison for Multimodal&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>SSE</th><th>WebSocket</th><th>WebRTC</th><th>WebTransport</th></tr></thead><tbody><tr><td>Direction</td><td>Server→Client</td><td>Bidirectional</td><td>Peer-to-peer</td><td>Bidirectional</td></tr><tr><td>Audio support</td><td>No (text only)</td><td>Yes (binary frames)</td><td>Native</td><td>Yes</td></tr><tr><td>Latency</td><td>Medium</td><td>Low</td><td>Very low</td><td>Very low</td></tr><tr><td>NAT traversal</td><td>N/A</td><td>N/A</td><td>Yes (ICE/STUN)</td><td>N/A</td></tr><tr><td>Complexity</td><td>Low</td><td>Medium</td><td>High</td><td>Medium</td></tr><tr><td>Browser support</td><td>Excellent</td><td>Excellent</td><td>Good</td><td>Emerging</td></tr></tbody></table><h3 id="future-protocol-directions" tabindex="-1">Future Protocol Directions <a class="header-anchor" href="#future-protocol-directions" aria-label="Permalink to &quot;Future Protocol Directions&quot;">​</a></h3><ul><li><strong>WebRTC</strong>: peer-to-peer voice and video with minimal server involvement</li><li><strong>WebTransport</strong>: HTTP/3-based low-latency bidirectional streaming</li><li><strong>QUIC</strong>: underlying transport for reduced connection establishment latency</li><li><strong>gRPC streaming</strong>: bidirectional streaming with strong typing (protobuf)</li><li>Trend: convergence toward single-connection multiplexed protocols</li><li>Challenge: balancing latency, reliability, and implementation complexity</li></ul><hr><h2 id="_10-integration-patterns" tabindex="-1">10. Integration Patterns <a class="header-anchor" href="#_10-integration-patterns" aria-label="Permalink to &quot;10. Integration Patterns&quot;">​</a></h2><h3 id="voice-code-agent-pipeline" tabindex="-1">Voice + Code Agent Pipeline <a class="header-anchor" href="#voice-code-agent-pipeline" aria-label="Permalink to &quot;Voice + Code Agent Pipeline&quot;">​</a></h3>',93)),(i(),s(u,null,{default:a(()=>[d(o,{id:"mermaid-1316",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5B%22Mic%20%2F%20Audio%20Capture%22%5D%20--%3E%20B%5B%22Whisper%20%2F%20STT%20Engine%22%5D%0A%20%20%20%20B%20--%3E%20C%5B%22LLM%20%2F%20Agent%22%5D%0A%20%20%20%20C%20--%3E%20D%5B%22Code%20Edit%20%26%20Apply%22%5D%0A%20%20%20%20C%20--%3E%20E%5B%22TTS%20%2F%20Voice%20Out%22%5D%0A%20%20%20%20E%20--%3E%20F%5B%22Speaker%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[c(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t(`<h3 id="multimodal-context-assembly" tabindex="-1">Multimodal Context Assembly <a class="header-anchor" href="#multimodal-context-assembly" aria-label="Permalink to &quot;Multimodal Context Assembly&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>User Input:</span></span>
<span class="line"><span>  ├── Text prompt: &quot;Fix the layout bug shown in this screenshot&quot;</span></span>
<span class="line"><span>  ├── Image: screenshot.png (base64-encoded, ~200KB)</span></span>
<span class="line"><span>  └── Code context: current file contents (auto-attached by agent)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>→ Assembled into single API request</span></span>
<span class="line"><span>→ Response streams as text tokens (code fix + explanation)</span></span></code></pre></div><h3 id="latency-budget-breakdown-voice-round-trip" tabindex="-1">Latency Budget Breakdown (Voice Round-Trip) <a class="header-anchor" href="#latency-budget-breakdown-voice-round-trip" aria-label="Permalink to &quot;Latency Budget Breakdown (Voice Round-Trip)&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Audio capture:           ~100ms  (utterance boundary detection)</span></span>
<span class="line"><span>Network upload:          ~50ms   (compressed audio payload)</span></span>
<span class="line"><span>Transcription (Whisper): ~1500ms (server-side processing)</span></span>
<span class="line"><span>LLM generation TTFT:     ~500ms (time to first token)</span></span>
<span class="line"><span>LLM streaming:           ~2000ms (full response)</span></span>
<span class="line"><span>TTS synthesis:           ~300ms  (if voice output enabled)</span></span>
<span class="line"><span>Audio playback start:    ~50ms</span></span>
<span class="line"><span>────────────────────────────────</span></span>
<span class="line"><span>Total:                   ~4500ms (end-to-end voice round-trip)</span></span></code></pre></div><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Voice and multimodal streaming extend coding agents beyond text-only interaction. The key technologies — Whisper for STT, Realtime/Live APIs for bidirectional voice, Vision APIs for image understanding — each add latency and complexity but unlock new interaction paradigms. The trajectory is clear: from text-only terminals toward rich, multimodal, conversational coding experiences. Accessibility is both a motivation and a beneficiary of these advances.</p>`,7))])}const w=n(p,[["render",m]]);export{x as __pageData,w as default};
